UPDATE story_events SET description = 'It was 2013 in the streets when someone called out "Maloba", and two strangers turned. Corine and Ruben, both carrying the same rare name, locked eyes for the first time. That single moment of curiosity sparked something neither could explain. They talked, they laughed, and without knowing it, they began a story that would cross oceans.' WHERE id = 'dc1d5a43-3229-4644-8a31-54851ddea2fe';